import sys
from collections import deque

def main():
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    A = list(map(int, data[1:]))

    if all(a == 1 for a in A):
        print("Yes")
        return

    # Create a queue for positions where A[i] is 0
    queue = deque()
    for i in range(N):
        if A[i] == 0:
            queue.append(i)

    # We'll use a visited array to track which positions have been processed
    visited = [False] * N

    while queue:
        i = queue.popleft()
        if visited[i]:
            continue
        visited[i] = True

        # Check if we can apply operation 1 on i (i.e., S_i=A, S_{i+1}=R, S_{i+2}=C)
        # This operation converts A[i] and A[i+1] to 1
        # But since the actual string S is not known, we simulate based on pattern
        # If A[i] is 0, and after processing, we can change it to 1
        if i + 1 < N and A[i] == 0:
            A[i] = 1
            if not visited[i + 1]:
                queue.append(i + 1)
        if i + 2 < N and A[i + 1] == 0:
            A[i + 1] = 1
            if not visited[i + 2]:
                queue.append(i + 2)

        # Check if we can apply operation 2 on i (i.e., S_{i+2}=A, S_{i+1}=R, S_i=C)
        # This requires checking that A[i] and A[i+1] are 0 and can be converted
        if i - 1 >= 0 and A[i] == 0:
            A[i] = 1
            if not visited[i + 1]:
                queue.append(i + 1)
        if i - 2 >= 0 and A[i + 1] == 0:
            A[i + 1] = 1
            if not visited[i + 2]:
                queue.append(i + 2)

    if all(a == 1 for a in A):
        print("Yes")
    else:
        print("No")

if __name__ == "__main__":
    main()
